### File 4: `packages/rest-client-generator/helpers/build.ts`

This is the key build config decision. The package has **two entry points**:

1. `src/index.ts` — the in-process library (CJS + ESM + types via `adapterConfig`)
2. `src/bin.ts` — the subprocess binary (CJS only, bundled, no types needed, with shebang)

Use `createAdapterConfig` for the library entry, and add a custom config for the bin (CJS, bundled, `emitTypes: false`, no `.mjs`):

```typescript
import { build } from '../../../helpers/compile/build'
import { createAdapterConfig } from '../../../helpers/compile/configs'

// Library entry: CJS + ESM + types
const libraryConfig = createAdapterConfig([{ entry: 'src/index.ts', outfile: 'dist/index' }])

// Bin entry: CJS only, bundled, no types
const binConfig = {
  name: 'bin',
  format: 'cjs' as const,
  bundle: true,
  entryPoints: ['src/bin.ts'],
  outfile: 'dist/bin',
  outExtension: { '.js': '.js' },
  emitTypes: false,
  banner: { js: '#!/usr/bin/env node' },
}

void build([...libraryConfig, binConfig])
```

The `banner` injects the shebang so the bin is directly executable. After build, the dist/bin.js file needs `chmod +x`. Since other packages do not add a post-build chmod here (only the CLI package does), add a small `onEnd` plugin or note that an `npm postbuild` script could do `chmod +x dist/bin.js`. The simpler approach consistent with the repo is to rely on `pnpm prepublishOnly` / OS file permissions being set at install time via the `bin` field in `package.json` (npm/pnpm sets execute bit on bin entries at install time automatically).

### File 5: `packages/rest-client-generator/src/typeMap.ts`

```typescript
import type * as DMMF from '@prisma/dmmf'

const SCALAR_MAP: Record<string, string> = {
  String: 'string',
  Boolean: 'boolean',
  Int: 'number',
  Float: 'number',
  BigInt: 'bigint',
  Decimal: 'string',
  DateTime: 'string',
  Json: 'unknown',
  Bytes: 'string',
}

export function prismaScalarToTs(field: DMMF.Field): string {
  if (field.kind === 'unsupported') return 'never'
  if (field.kind === 'object') return field.type // relation — caller should filter these out
  if (field.kind === 'enum') return field.type   // enum name as-is
  // scalar
  const mapped = SCALAR_MAP[field.type] ?? 'unknown'
  return field.isList ? `Array<${mapped}>` : mapped
}

/** Wraps a TS type string to be nullable if the field is not required */
export function withNullability(tsType: string, field: DMMF.Field): string {
  return field.isRequired ? tsType : `${tsType} | null`
}
```

### File 6: `packages/rest-client-generator/src/utils.ts`

```typescript
/** Inline parseEnvValue — avoids @prisma/internals dependency */
export function parseEnvValue(obj: { fromEnvVar: string | null; value: string | null }): string {
  if (obj.fromEnvVar && obj.fromEnvVar !== 'null') {
    const val = process.env[obj.fromEnvVar]
    if (!val) throw new Error(`env var ${obj.fromEnvVar} not set`)
    return val
  }
  return obj.value as string
}

/** Converts a PascalCase model name to a lowercase kebab/plural REST path segment */
export function modelNameToRoute(modelName: string): string {
  const lower = modelName.toLowerCase()
  if (/[sxz]$/.test(lower) || /ch$/.test(lower) || /sh$/.test(lower)) {
    return lower + 'es'
  }
  if (/[^aeiou]y$/.test(lower)) {
    return lower.slice(0, -1) + 'ies'
  }
  return lower + 's'
}
```

### File 7: `packages/rest-client-generator/src/generateTypes.ts`

Responsible for producing the `types.ts` string.

```typescript
import type * as DMMF from '@prisma/dmmf'
import { prismaScalarToTs, withNullability } from './typeMap'

export function generateTypesFile(datamodel: DMMF.Datamodel): string {
  const lines: string[] = [
    '// GENERATED — do not edit manually',
    '// Generated by @prisma/rest-client-generator',
    '',
  ]

  // Enums → string unions
  for (const enumDef of datamodel.enums) {
    const values = enumDef.values.map((v) => JSON.stringify(v.name)).join(' | ')
    lines.push(`export type ${enumDef.name} = ${values}`, '')
  }

  // Models → interfaces (scalar + enum fields only)
  for (const model of datamodel.models) {
    lines.push(`export interface ${model.name} {`)
    for (const field of model.fields) {
      if (field.kind === 'object' || field.kind === 'unsupported') continue
      const tsType = withNullability(prismaScalarToTs(field), field)
      lines.push(`  ${field.name}: ${tsType}`)
    }
    lines.push('}', '')
  }

  return lines.join('\n')
}
```

### File 8: `packages/rest-client-generator/src/generateModel.ts`

Produces the per-model `<ModelName>.ts` string.

```typescript
import type * as DMMF from '@prisma/dmmf'
import { prismaScalarToTs, withNullability } from './typeMap'
import { modelNameToRoute } from './utils'

function getIdField(model: DMMF.Model): DMMF.Field | undefined {
  return model.fields.find((f) => f.isId && (f.kind === 'scalar' || f.kind === 'enum'))
}

function getUniqueFields(model: DMMF.Model): DMMF.Field[] {
  return model.fields.filter(
    (f) => f.isUnique && !f.isId && (f.kind === 'scalar' || f.kind === 'enum'),
  )
}

export function generateModelFile(model: DMMF.Model): string {
  const modelName = model.name
  const route = modelNameToRoute(modelName)
  const idField = getIdField(model)
  const uniqueFields = getUniqueFields(model)

  const lines: string[] = [
    '// GENERATED — do not edit manually',
    '// Generated by @prisma/rest-client-generator',
    '',
    `import type { ${modelName} } from './types'`,
    '',
  ]

  // --- WhereUniqueInput ---
  lines.push(`export interface ${modelName}WhereUniqueInput {`)
  if (idField) {
    lines.push(`  ${idField.name}: ${prismaScalarToTs(idField)}`)
  }
  for (const f of uniqueFields) {
    lines.push(`  ${f.name}?: ${prismaScalarToTs(f)}`)
  }
  lines.push('}', '')

  // --- CreateInput ---
  lines.push(`export interface ${modelName}CreateInput {`)
  for (const field of model.fields) {
    if (field.kind === 'object' || field.kind === 'unsupported') continue
    const isAutomatic = field.hasDefaultValue || field.isUpdatedAt || field.isGenerated
    const tsType = prismaScalarToTs(field)
    const nullable = !field.isRequired ? ` | null` : ''
    const optional = isAutomatic || !field.isRequired ? '?' : ''
    lines.push(`  ${field.name}${optional}: ${tsType}${nullable}`)
  }
  lines.push('}', '')

  // --- UpdateInput ---
  lines.push(`export interface ${modelName}UpdateInput {`)
  for (const field of model.fields) {
    if (field.kind === 'object' || field.kind === 'unsupported') continue
    const tsType = prismaScalarToTs(field)
    const nullable = !field.isRequired ? ` | null` : ''
    lines.push(`  ${field.name}?: ${tsType}${nullable}`)
  }
  lines.push('}', '')

  // --- Client class ---
  const idFieldName = idField?.name ?? 'id'
  lines.push(
    `export class ${modelName}RestClient {`,
    `  constructor(private readonly baseUrl: string) {}`,
    ``,
    `  private get base(): string {`,
    `    return \`\${this.baseUrl}/${route}\``,
    `  }`,
    ``,
    `  async findMany(): Promise<${modelName}[]> {`,
    `    const res = await fetch(this.base)`,
    `    if (!res.ok) throw new Error(\`GET \${this.base} failed: \${res.status}\`)`,
    `    return res.json() as Promise<${modelName}[]>`,
    `  }`,
    ``,
    `  async findUnique(where: ${modelName}WhereUniqueInput): Promise<${modelName} | null> {`,
    `    const url = \`\${this.base}/\${encodeURIComponent(String(where.${idFieldName}))}\``,
    `    const res = await fetch(url)`,
    `    if (res.status === 404) return null`,
    `    if (!res.ok) throw new Error(\`GET \${url} failed: \${res.status}\`)`,
    `    return res.json() as Promise<${modelName}>`,
    `  }`,
    ``,
    `  async create(data: ${modelName}CreateInput): Promise<${modelName}> {`,
    `    const res = await fetch(this.base, {`,
    `      method: 'POST',`,
    `      headers: { 'Content-Type': 'application/json' },`,
    `      body: JSON.stringify(data),`,
    `    })`,
    `    if (!res.ok) throw new Error(\`POST \${this.base} failed: \${res.status}\`)`,
    `    return res.json() as Promise<${modelName}>`,
    `  }`,
    ``,
    `  async update(where: ${modelName}WhereUniqueInput, data: ${modelName}UpdateInput): Promise<${modelName}> {`,
    `    const url = \`\${this.base}/\${encodeURIComponent(String(where.${idFieldName}))}\``,
    `    const res = await fetch(url, {`,
    `      method: 'PATCH',`,
    `      headers: { 'Content-Type': 'application/json' },`,
    `      body: JSON.stringify(data),`,
    `    })`,
    `    if (!res.ok) throw new Error(\`PATCH \${url} failed: \${res.status}\`)`,
    `    return res.json() as Promise<${modelName}>`,
    `  }`,
    ``,
    `  async delete(where: ${modelName}WhereUniqueInput): Promise<${modelName}> {`,
    `    const url = \`\${this.base}/\${encodeURIComponent(String(where.${idFieldName}))}\``,
    `    const res = await fetch(url, { method: 'DELETE' })`,
    `    if (!res.ok) throw new Error(\`DELETE \${url} failed: \${res.status}\`)`,
    `    return res.json() as Promise<${modelName}>`,
    `  }`,
    `}`,
  )

  return lines.join('\n')
}
```

