```typescript
import { build } from '../../../helpers/compile/build'
import { createAdapterConfig } from '../../../helpers/compile/configs'

// Library entry: CJS + ESM + types
const libraryConfig = createAdapterConfig([{ entry: 'src/index.ts', outfile: 'dist/index' }])

// Bin entry: CJS only, bundled, no types
const binConfig = {
  name: 'bin',
  format: 'cjs' as const,
  bundle: true,
