```typescript
import type * as DMMF from '@prisma/dmmf'

const SCALAR_MAP: Record<string, string> = {
  String: 'string',
  Boolean: 'boolean',
  Int: 'number',
  Float: 'number',
  BigInt: 'bigint',
  Decimal: 'string',
  DateTime: 'string',
  Json: 'unknown',
  Bytes: 'string',
}

export function prismaScalarToTs(field: DMMF.Field): string {
  if (field.kind === 'unsupported') return 'never'
  if (field.kind === 'object') return field.type // relation — caller should filter these out
  if (field.kind === 'enum') return field.type   // enum name as-is
  // scalar
  const mapped = SCALAR_MAP[field.type] ?? 'unknown'
  return field.isList ? `Array<${mapped}>` : mapped
}

/** Wraps a TS type string to be nullable if the field is not required */
export function withNullability(tsType: string, field: DMMF.Field): string {
  return field.isRequired ? tsType : `${tsType} | null`
}
