/** Inline parseEnvValue — avoids @prisma/internals dependency */
export function parseEnvValue(obj: { fromEnvVar: string | null; value: string | null }): string {
  if (obj.fromEnvVar && obj.fromEnvVar !== 'null') {
    const val = process.env[obj.fromEnvVar]
    if (!val) throw new Error(`env var ${obj.fromEnvVar} not set`)
    return val
  }
  return obj.value as string
}

/** Converts a PascalCase model name to a lowercase kebab/plural REST path segment */
export function modelNameToRoute(modelName: string): string {
  const lower = modelName.toLowerCase()
  if (/[sxz]$/.test(lower) || /ch$/.test(lower) || /sh$/.test(lower)) {
    return lower + 'es'
  }
  if (/[^aeiou]y$/.test(lower)) {
    return lower.slice(0, -1) + 'ies'
  }
  return lower + 's'
}
