```typescript
import type * as DMMF from '@prisma/dmmf'
import { prismaScalarToTs, withNullability } from './typeMap'

export function generateTypesFile(datamodel: DMMF.Datamodel): string {
  const lines: string[] = [
    '// GENERATED — do not edit manually',
    '// Generated by @prisma/rest-client-generator',
    '',
  ]

  // Enums → string unions
  for (const enumDef of datamodel.enums) {
    const values = enumDef.values.map((v) => JSON.stringify(v.name)).join(' | ')
    lines.push(`export type ${enumDef.name} = ${values}`, '')
  }

  // Models → interfaces (scalar + enum fields only)
  for (const model of datamodel.models) {
    lines.push(`export interface ${model.name} {`)
    for (const field of model.fields) {
      if (field.kind === 'object' || field.kind === 'unsupported') continue
      const tsType = withNullability(prismaScalarToTs(field), field)
      lines.push(`  ${field.name}: ${tsType}`)
    }
    lines.push('}', '')
  }

  return lines.join('\n')
}
