```typescript
import type * as DMMF from '@prisma/dmmf'
import { prismaScalarToTs, withNullability } from './typeMap'
import { modelNameToRoute } from './utils'

function getIdField(model: DMMF.Model): DMMF.Field | undefined {
  return model.fields.find((f) => f.isId && (f.kind === 'scalar' || f.kind === 'enum'))
}

function getUniqueFields(model: DMMF.Model): DMMF.Field[] {
  return model.fields.filter(
    (f) => f.isUnique && !f.isId && (f.kind === 'scalar' || f.kind === 'enum'),
  )
}

export function generateModelFile(model: DMMF.Model): string {
  const modelName = model.name
  const route = modelNameToRoute(modelName)
  const idField = getIdField(model)
  const uniqueFields = getUniqueFields(model)

  const lines: string[] = [
    '// GENERATED — do not edit manually',
    '// Generated by @prisma/rest-client-generator',
    '',
    `import type { ${modelName} } from './types'`,
    '',
  ]

  // --- WhereUniqueInput ---
  lines.push(`export interface ${modelName}WhereUniqueInput {`)
  if (idField) {
    lines.push(`  ${idField.name}: ${prismaScalarToTs(idField)}`)
  }
  for (const f of uniqueFields) {
    lines.push(`  ${f.name}?: ${prismaScalarToTs(f)}`)
  }
  lines.push('}', '')

  // --- CreateInput ---
  lines.push(`export interface ${modelName}CreateInput {`)
  for (const field of model.fields) {
    if (field.kind === 'object' || field.kind === 'unsupported') continue
    const isAutomatic = field.hasDefaultValue || field.isUpdatedAt || field.isGenerated
    const tsType = prismaScalarToTs(field)
    const nullable = !field.isRequired ? ` | null` : ''
    const optional = isAutomatic || !field.isRequired ? '?' : ''
    lines.push(`  ${field.name}${optional}: ${tsType}${nullable}`)
  }
  lines.push('}', '')

  // --- UpdateInput ---
  lines.push(`export interface ${modelName}UpdateInput {`)
  for (const field of model.fields) {
    if (field.kind === 'object' || field.kind === 'unsupported') continue
    const tsType = prismaScalarToTs(field)
    const nullable = !field.isRequired ? ` | null` : ''
    lines.push(`  ${field.name}?: ${tsType}${nullable}`)
  }
  lines.push('}', '')

  // --- Client class ---
  const idFieldName = idField?.name ?? 'id'
  lines.push(
    `export class ${modelName}RestClient {`,
    `  constructor(private readonly baseUrl: string) {}`,
    ``,
    `  private get base(): string {`,
    `    return \`\${this.baseUrl}/${route}\``,
    `  }`,
    ``,
    `  async findMany(): Promise<${modelName}[]> {`,
    `    const res = await fetch(this.base)`,
    `    if (!res.ok) throw new Error(\`GET \${this.base} failed: \${res.status}\`)`,
    `    return res.json() as Promise<${modelName}[]>`,
    `  }`,
    ``,
    `  async findUnique(where: ${modelName}WhereUniqueInput): Promise<${modelName} | null> {`,
    `    const url = \`\${this.base}/\${encodeURIComponent(String(where.${idFieldName}))}\``,
    `    const res = await fetch(url)`,
    `    if (res.status === 404) return null`,
    `    if (!res.ok) throw new Error(\`GET \${url} failed: \${res.status}\`)`,
    `    return res.json() as Promise<${modelName}>`,
    `  }`,
    ``,
    `  async create(data: ${modelName}CreateInput): Promise<${modelName}> {`,
    `    const res = await fetch(this.base, {`,
    `      method: 'POST',`,
    `      headers: { 'Content-Type': 'application/json' },`,
    `      body: JSON.stringify(data),`,
    `    })`,
    `    if (!res.ok) throw new Error(\`POST \${this.base} failed: \${res.status}\`)`,
    `    return res.json() as Promise<${modelName}>`,
    `  }`,
    ``,
    `  async update(where: ${modelName}WhereUniqueInput, data: ${modelName}UpdateInput): Promise<${modelName}> {`,
    `    const url = \`\${this.base}/\${encodeURIComponent(String(where.${idFieldName}))}\``,
    `    const res = await fetch(url, {`,
    `      method: 'PATCH',`,
    `      headers: { 'Content-Type': 'application/json' },`,
    `      body: JSON.stringify(data),`,
    `    })`,
    `    if (!res.ok) throw new Error(\`PATCH \${url} failed: \${res.status}\`)`,
    `    return res.json() as Promise<${modelName}>`,
    `  }`,
    ``,
    `  async delete(where: ${modelName}WhereUniqueInput): Promise<${modelName}> {`,
    `    const url = \`\${this.base}/\${encodeURIComponent(String(where.${idFieldName}))}\``,
    `    const res = await fetch(url, { method: 'DELETE' })`,
    `    if (!res.ok) throw new Error(\`DELETE \${url} failed: \${res.status}\`)`,
    `    return res.json() as Promise<${modelName}>`,
    `  }`,
    `}`,
  )

  return lines.join('\n')
}
