  const idField = getIdField(model)
  if (idField) return idField.name

  if (model.primaryKey?.fields?.length) return model.primaryKey.fields[0]

  const firstScalar = model.fields.find((f) => f.kind === 'scalar')
  return firstScalar?.name ?? 'id'
}

