import fs from 'node:fs'
import os from 'node:os'
import path from 'node:path'

import type * as DMMF from '@prisma/dmmf'
import type { GeneratorOptions } from '@prisma/generator'
import { afterEach, beforeEach, describe, expect, test } from 'vitest'

import { generateIndexFile } from '../generate-index'
import { generateModelFile } from '../generate-model'
import { generateTypesFile } from '../generate-types'
import { RestClientGenerator } from '../generator'
import { modelNameToRoute } from '../utils'

// ---------------------------------------------------------------------------
// Minimal DMMF fixture
// ---------------------------------------------------------------------------

const fakeField = (overrides: Partial<DMMF.Field>): DMMF.Field =>
  ({
    kind: 'scalar',
    name: 'unknown',
    isRequired: true,
    isList: false,
    isUnique: false,
    isId: false,
    isReadOnly: false,
    isGenerated: false,
    isUpdatedAt: false,
    type: 'String',
    hasDefaultValue: false,
    ...overrides,
  }) as unknown as DMMF.Field

const fakeDatamodel: DMMF.Datamodel = {
  models: [
    {
      name: 'User',
      dbName: null,
      schema: null,
      primaryKey: null,
      uniqueFields: [['email']],
      uniqueIndexes: [],
      fields: [
        fakeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
        fakeField({ name: 'email', type: 'String', isUnique: true }),
        fakeField({ name: 'name', type: 'String', isRequired: false }),
        fakeField({ name: 'role', kind: 'enum', type: 'Role', hasDefaultValue: true }),
        // relation field — should be excluded from output
        fakeField({ name: 'posts', kind: 'object', type: 'Post', isList: true }),
      ],
    },
  ],
  enums: [
    {
      name: 'Role',
      values: [
        { name: 'ADMIN', dbName: null },
        { name: 'USER', dbName: null },
      ],
    },
  ],
  types: [],
  indexes: [],
} as unknown as DMMF.Datamodel

function makeOptions(outputDir: string): GeneratorOptions {
  return {
    generator: {
      name: 'restClient',
      provider: { fromEnvVar: null, value: 'prisma-rest-client' },
      output: { fromEnvVar: null, value: outputDir },
      config: {},
      binaryTargets: [],
      previewFeatures: [],
      sourceFilePath: '/fake/schema.prisma',
    },
    otherGenerators: [],
    schemaPath: '/fake/schema.prisma',
    dmmf: {
      datamodel: fakeDatamodel,
      schema: {} as never,
      mappings: {} as never,
    },
    datasources: [],
    datamodel: '',
    version: 'test',
  }
}

// ---------------------------------------------------------------------------
// Tests
// ---------------------------------------------------------------------------

describe('RestClientGenerator.getManifest', () => {
  test('returns expected manifest shape', async () => {
    const gen = new RestClientGenerator()
    const manifest = await gen.getManifest({} as never)
    expect(manifest.prettyName).toBe('Prisma REST Client')
    expect(manifest.defaultOutput).toBe('./generated/rest-client')
    expect(manifest.requiresEngines).toEqual([])
  })
})

describe('RestClientGenerator.generate', () => {
  let tmpDir: string

  beforeEach(() => {
    tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), 'rest-client-gen-'))
  })

  afterEach(() => {
    fs.rmSync(tmpDir, { recursive: true, force: true })
  })

  test('throws when output is missing', async () => {
    const gen = new RestClientGenerator()
    const opts = makeOptions(tmpDir)
    opts.generator.output = null
    await expect(gen.generate(opts)).rejects.toThrow('output path is required')
  })

  test('creates output directory if it does not exist', async () => {
    const gen = new RestClientGenerator()
    const nested = path.join(tmpDir, 'deep', 'nested', 'output')
    await gen.generate(makeOptions(nested))
    expect(fs.existsSync(nested)).toBe(true)
  })

  test('writes types.ts', async () => {
    const gen = new RestClientGenerator()
    await gen.generate(makeOptions(tmpDir))
    expect(fs.existsSync(path.join(tmpDir, 'types.ts'))).toBe(true)
  })

  test('writes one file per model', async () => {
    const gen = new RestClientGenerator()
    await gen.generate(makeOptions(tmpDir))
    expect(fs.existsSync(path.join(tmpDir, 'User.ts'))).toBe(true)
  })

  test('writes index.ts', async () => {
    const gen = new RestClientGenerator()
    await gen.generate(makeOptions(tmpDir))
    expect(fs.existsSync(path.join(tmpDir, 'index.ts'))).toBe(true)
  })
})

// ---------------------------------------------------------------------------
// generateTypesFile
// ---------------------------------------------------------------------------

describe('generateTypesFile', () => {
  test('generates enum as string union with JSON-quoted values', () => {
    const result = generateTypesFile(fakeDatamodel)
    expect(result).toContain("export type Role = 'ADMIN' | 'USER'")
  })

  test('generates model interface with scalar and enum fields', () => {
    const result = generateTypesFile(fakeDatamodel)
    expect(result).toContain('export interface User {')
    expect(result).toContain('id: number')
    expect(result).toContain('email: string')
    expect(result).toContain('role: Role')
  })

  test('marks non-required fields as nullable', () => {
    const result = generateTypesFile(fakeDatamodel)
    expect(result).toContain('name: string | null')
  })

  test('excludes relation (object) fields', () => {
    const result = generateTypesFile(fakeDatamodel)
    expect(result).not.toContain('posts')
  })
})

// ---------------------------------------------------------------------------
// generateModelFile
// ---------------------------------------------------------------------------

describe('generateModelFile', () => {
  const model = fakeDatamodel.models[0]

  test('imports from types', () => {
    const result = generateModelFile(model)
    expect(result).toContain("import type { User } from './types'")
  })

  test('generates WhereUniqueInput with id as required and unique fields as optional', () => {
    const result = generateModelFile(model)
    expect(result).toContain('export interface UserWhereUniqueInput {')
    expect(result).toContain('  id: number')
    expect(result).toContain('  email?: string')
  })

  test('generates CreateInput — auto fields optional, required fields required', () => {
    const result = generateModelFile(model)
    expect(result).toContain('export interface UserCreateInput {')
    // id has hasDefaultValue=true → optional
    expect(result).toContain('  id?:')
    // email is required and has no default → required
    expect(result).toContain('  email: string')
    // role has hasDefaultValue=true → optional
    expect(result).toContain('  role?:')
  })

  test('generates UpdateInput with all fields optional', () => {
    const result = generateModelFile(model)
    expect(result).toContain('export interface UserUpdateInput {')
    expect(result).toContain('  id?:')
    expect(result).toContain('  email?:')
  })

  test('excludes relation (object) fields from all input types', () => {
    const result = generateModelFile(model)
    // 'posts' is a relation and must not appear in any input interface
    const inputSection = result.split('export class')[0]
    expect(inputSection).not.toContain('posts')
  })

  test('generates RestClient class with all five CRUD methods', () => {
    const result = generateModelFile(model)
    expect(result).toContain('export class UserRestClient {')
    expect(result).toContain('async findMany()')
    expect(result).toContain('async findUnique(')
    expect(result).toContain('async create(')
    expect(result).toContain('async update(')
    expect(result).toContain('async delete(')
  })

  test('uses correct plural route path in client', () => {
    const result = generateModelFile(model)
    expect(result).toContain('/users')
  })

  test('uses id field name in URL construction', () => {
    const result = generateModelFile(model)
    expect(result).toContain('where.id')
  })
})

// ---------------------------------------------------------------------------
// generateIndexFile
// ---------------------------------------------------------------------------

describe('generateIndexFile', () => {
  test('re-exports types and each model', () => {
    const result = generateIndexFile(fakeDatamodel)
    expect(result).toContain("export * from './types'")
    expect(result).toContain("export * from './User'")
  })
})

// ---------------------------------------------------------------------------
// modelNameToRoute
// ---------------------------------------------------------------------------

describe('modelNameToRoute', () => {
  test('appends s for regular names', () => {
    expect(modelNameToRoute('User')).toBe('users')
    expect(modelNameToRoute('Post')).toBe('posts')
  })

  test('appends es for names ending in s, x, z', () => {
    expect(modelNameToRoute('Box')).toBe('boxes')
    expect(modelNameToRoute('Status')).toBe('statuses')
    expect(modelNameToRoute('Quiz')).toBe('quizzes')
  })

  test('appends es for names ending in ch or sh', () => {
    expect(modelNameToRoute('Witch')).toBe('witches')
    expect(modelNameToRoute('Dish')).toBe('dishes')
  })

  test('replaces y with ies for names ending in consonant+y', () => {
    expect(modelNameToRoute('Category')).toBe('categories')
    expect(modelNameToRoute('Story')).toBe('stories')
  })

  test('does not replace y when preceded by a vowel', () => {
    // "day" ends in vowel+y → just append s
    expect(modelNameToRoute('Holiday')).toBe('holidays')
  })
})

